/**
 * MedX high-contrast accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Forced-colors and high contrast mode.
 */
const HIGH_CONTRAST_TOKENS = Object.freeze({
  primary: { value: "a11y-high-contrast-primary", scope: "a11y" },
  secondary: { value: "a11y-high-contrast-secondary", scope: "a11y" },
  muted: { value: "a11y-high-contrast-muted", scope: "a11y" },
  accent: { value: "a11y-high-contrast-accent", scope: "a11y" },
  surface: { value: "a11y-high-contrast-surface", scope: "a11y" },
});

const HIGH_CONTRAST_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const HIGH_CONTRAST_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const highcontrastRegistry = new Map();
const HIGH_CONTRAST_listeners = new Set();
let HIGH_CONTRAST_seq = 0;

function createHighContrastId(prefix = "medx-a11y-high-contrast") {
  HIGH_CONTRAST_seq += 1;
  return `${prefix}-${HIGH_CONTRAST_seq}`;
}

function registerHighContrast(config = {}) {
  const entryId = config.id ?? createHighContrastId();
  const preset = HIGH_CONTRAST_PRESETS[config.preset ?? "default"] ?? HIGH_CONTRAST_PRESETS.default;
  const token = HIGH_CONTRAST_TOKENS[config.token ?? preset.token] ?? HIGH_CONTRAST_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: HIGH_CONTRAST_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  highcontrastRegistry.set(entryId, entry);
  notifyHighContrastListeners("register", entry);
  return entry;
}

function updateHighContrast(id, patch = {}) {
  const entry = highcontrastRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyHighContrastListeners("update", entry);
  return entry;
}

function resolveHighContrast(id) {
  const entry = highcontrastRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listHighContrastEntries(filter = {}) {
  let items = Array.from(highcontrastRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onHighContrastEvent(listener) {
  HIGH_CONTRAST_listeners.add(listener);
  return () => HIGH_CONTRAST_listeners.delete(listener);
}

function notifyHighContrastListeners(type, entry) {
  for (const listener of HIGH_CONTRAST_listeners) {
    try {
      listener({ type, entry, registrySize: highcontrastRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:high-contrast] listener error", err.message);
    }
  }
}

function getHighContrastMetrics() {
  const items = listHighContrastEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(HIGH_CONTRAST_TOKENS).length,
    presets: Object.keys(HIGH_CONTRAST_PRESETS).length,
  };
}

async function runMedxHighContrast() {
  console.log("[medx:ui:a11y:high-contrast] runtime initialized");
  console.log(`[medx:ui:a11y:high-contrast] tokens=${Object.keys(HIGH_CONTRAST_TOKENS).length} presets=${Object.keys(HIGH_CONTRAST_PRESETS).length}`);

  const events = [];
  onHighContrastEvent((e) => events.push(e.type));

  const domains = Object.keys(HIGH_CONTRAST_SUPPLY_CHAIN);
  const presets = Object.keys(HIGH_CONTRAST_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerHighContrast({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/high-contrast" },
    });
  }

  const first = listHighContrastEntries()[0];
  if (first) updateHighContrast(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getHighContrastMetrics();
  const resolved = first ? resolveHighContrast(first.id) : null;

  console.log(`[medx:ui:a11y:high-contrast] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:high-contrast] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:high-contrast] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:high-contrast] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:high-contrast] bootstrap complete");
}

module.exports = runMedxHighContrast;
